trigger AccountTrigger on Account (before update) {
    for (Account acct : Trigger.new) {
        Account oldAccount = Trigger.oldMap.get(acct.Id);
        if (acct.ShippingState != oldAccount.ShippingState) {
            acct.BillingState = acct.ShippingState;
        }
    }
}

Set<Id> accountIds = new Set<Id>();
for (Account acct : accounts) {
    accountIds.add(acct.Id);
}

Map<Id, List<Contact>> accountIdToContacts = new Map<Id, List<Contact>>();
List<Contact> contacts = [
    SELECT Id, MailingState, AccountId
    FROM Contact
    WHERE AccountId IN :accountIds
];
for (Contact con : contacts) {
    if (!accountIdToContacts.containsKey(con.AccountId)) {
        accountIdToContacts.put(con.AccountId, new List<Contact>());
    }
    accountIdToContacts.get(con.AccountId).add(con);
}

trigger AccountTrigger on Account (before insert, before update, after insert, after update) {
    if (Trigger.isBefore) {
        AccountTriggerHandler.handleBeforeTrigger(Trigger.new, Trigger.oldMap);
    } else if (Trigger.isAfter) {
        AccountTriggerHandler.handleAfterTrigger(Trigger.new, Trigger.oldMap);
    }
}

public class AccountTriggerHandler {
    public static void handleBeforeTrigger(List<Account> accounts, Map<Id, Account> oldMap) {
        matchBillingToShipping(accounts, oldMap);
    }
    public static void handleAfterTrigger(List<Account> accounts, Map<Id, Account> oldMap) {
        // post-DML logic — updating related contacts, async jobs, etc.
    }
    public static void matchBillingToShipping(List<Account> accounts, Map<Id, Account> oldMap) {
        for (Account acct : accounts) {
            Account oldAcct = oldMap.get(acct.Id);
            if (acct.ShippingState != oldAcct.ShippingState) {
                acct.BillingState = acct.ShippingState;
            }
        }
    }
}

trigger CaseTrigger on Case (before insert, after insert) {
    if (Trigger.isBefore && Trigger.isInsert) {
        for (Case c : Trigger.new) {
            if (c.Priority == null) {
                c.Priority = 'Medium';
            }
        }
    }
    if (Trigger.isAfter && Trigger.isInsert) {
        Set<Id> caseIds = new Set<Id>();
        for (Case c : Trigger.new) {
            caseIds.add(c.Id);
        }
        System.enqueueJob(new CaseNotificationJob(caseIds));
    }
}
